import{_ as r,o as a,c as l,ae as e}from"./chunks/framework.DAK3ioSj.js";const g=JSON.parse('{"title":"SkillClaw","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillclaw.md","filePath":"radar/tech-skillclaw.md"}'),o={name:"radar/tech-skillclaw.md"};function n(i,t,d,s,h,u){return a(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="skillclaw" tabindex="-1">SkillClaw <a class="header-anchor" href="#skillclaw" aria-label="Permalink to &quot;SkillClaw&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 优化 / Skill 管理 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.55</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>后台守护进程</strong>静默聚合多用户的所有 Agent 轨迹 → 识别跨用户重复模式 → 进化 Skill → 同步回全用户。</p><p><strong>来源</strong>:</p><ul><li>AMAP-ML（阿里高德地图）</li><li>论文 + 开源</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2604.08377" target="_blank" rel="noreferrer">arXiv 2604.08377</a></li><li>GitHub：<a href="https://github.com/AMAP-ML/SkillClaw" target="_blank" rel="noreferrer">AMAP-ML/SkillClaw</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="三阶段管线" tabindex="-1">三阶段管线 <a class="header-anchor" href="#三阶段管线" aria-label="Permalink to &quot;三阶段管线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>行为</th></tr></thead><tbody><tr><td><strong>① 结构化会话收集</strong></td><td>用户 prompt → Agent 动作 → 中间反馈 → 最终答案，所有用户轨迹汇入同一证据池</td></tr><tr><td><strong>② Agentic Evolver 识别模式</strong></td><td>自主推理引擎分析所有轨迹，识别<strong>跨用户反复出现的行为模式</strong>（如 5 个工程师独立发现&quot;先备份 → 分块 → 合并&quot;三步流程 → 提炼为 Skill）</td></tr><tr><td><strong>③ 共享仓库同步</strong></td><td>进化后的 Skill 存入共享仓库，自动同步到所有用户的所有 Agent 实例</td></tr></tbody></table><h3 id="关键设计洞察" tabindex="-1">关键设计洞察 <a class="header-anchor" href="#关键设计洞察" aria-label="Permalink to &quot;关键设计洞察&quot;">​</a></h3><blockquote><p>单个用户很少产生足够信号区分&quot;可泛化改进&quot;和&quot;特定场景补丁&quot;，但聚合多用户互补视角后，哪些模式真正通用就变得清晰。</p></blockquote><p>原生集成 Hermes / OpenClaw / QwenPaw 以及任何 OpenAI 兼容 API。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li><strong>仅在 Qwen3-Max 上验证</strong></li><li><strong>隐私和冲突解决未详述</strong> —— 当不同用户经验矛盾时（&quot;日志流式读取更快&quot; vs &quot;全量读取更稳定&quot;），SkillClaw 强制合并为统一 Skill，<strong>缺乏分支或覆盖机制</strong></li><li><strong>企业保密场景顾虑</strong> —— 多用户轨迹汇聚意味着 A 的操作模式对 B 间接可见</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文 + 开源</td></tr><tr><td>创新性</td><td>0.75</td><td>多用户集体进化是独有路径</td></tr><tr><td>落地程度</td><td>0.40</td><td>仅 AMAP 内部验证</td></tr><tr><td>生态活跃度</td><td>0.50</td><td>仓库较新，社区扩散中</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.55</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2604.08377" target="_blank" rel="noreferrer">SkillClaw 论文</a></li><li><a href="https://github.com/AMAP-ML/SkillClaw" target="_blank" rel="noreferrer">GitHub</a></li><li><a href="https://eu.36kr.com/en/p/3767753692201481" target="_blank" rel="noreferrer">36kr 解析</a></li></ul>',27)])])}const b=r(o,[["render",n]]);export{g as __pageData,b as default};
